import { useRef, useEffect } from "react";
import maplibregl from "maplibre-gl";
import "maplibre-gl/dist/maplibre-gl.css";

export function MapView() {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!ref.current) return;
    const map = new maplibregl.Map({
      container: ref.current,
      style: "https://demotiles.maplibre.org/style.json",
      center: [69.24, 41.31],   // Toshkent — [lng, lat]
      zoom: 11,
    });
    return () => map.remove();   // tozalash — muhim!
  }, []);

  return <div ref={ref} style={{ width: "100%", height: "100vh" }} />;
}

map.on("load", () => {
  map.addSource("osm", {
    type: "vector",
    tiles: ["https://your-domain.com/tiles/osm/{z}/{x}/{y}.pbf"],
  });
  map.addLayer({
    id: "buildings",
    type: "fill",
    source: "osm",
    "source-layer": "buildings",     // tegola layer nomi
    paint: { "fill-color": "#34D6C0", "fill-opacity": 0.5 },
  });
});

map.on("load", () => {
  map.addSource("api-buildings", {
    type: "geojson",
    data: { type: "FeatureCollection", features: [] },
  });
  map.addLayer({
    id: "api-fill", type: "fill", source: "api-buildings",
    paint: { "fill-color": "#F4A23C", "fill-opacity": 0.4 },
  });

  const refresh = async () => {
    const b = map.getBounds();
    const bbox = [b.getWest(), b.getSouth(), b.getEast(), b.getNorth()].join(",");
    const res = await fetch(`/api/buildings?bbox=${bbox}`);
    const geojson = await res.json();
    (map.getSource("api-buildings") as maplibregl.GeoJSONSource).setData(geojson);
  };

  map.on("moveend", refresh);   // har harakatdan keyin
  refresh();                     // boshlang'ich yuk
});

async function search(q: string) {
  const res = await fetch(`/api/search?q=${encodeURIComponent(q)}`);
  const fc = await res.json();
  const f = fc.features[0];
  if (!f) return;
  const [lng, lat] = f.geometry.coordinates;
  map.flyTo({ center: [lng, lat], zoom: 16 });
  new maplibregl.Popup()
    .setLngLat([lng, lat])
    .setHTML(`<b>${f.properties.name}</b>`)
    .addTo(map);
}

