import { Injectable } from "@nestjs/common";
import { Pool } from "pg";

@Injectable()
export class BuildingsService {
  private pool = new Pool({ connectionString: process.env.DATABASE_URL });

  async findInBbox(b: number[]) {
    const sql = `
      SELECT id, name, height, ST_AsGeoJSON(geometry)::json AS geometry
      FROM buildings
      WHERE ST_Intersects(geometry, ST_MakeEnvelope($1,$2,$3,$4,4326))
      LIMIT 500`;
    const { rows } = await this.pool.query(sql, b);
    return { type: "FeatureCollection",
             features: rows.map(r => ({ type: "Feature",
               geometry: r.geometry,
               properties: { id: r.id, name: r.name, height: r.height } })) };
  }
}

